import { useEffect } from "react";

// ── Placeholders — swap with your actual imports ──────────────
const mumbaiBg = "/assets/journey/mumbai/mumbaibg.png";
const flowerTopRight = "/assets/journey/mumbai/mumbaiflower.png";
const flowerBottomLeft = "/assets/journey/mumbai/mumbaiflower.png";

const MENU_ITEMS = [
  { name: "DAL BATI CHURMA", price: 15 },
  { name: "LAAL MAAS", price: 25 },
  { name: "GATTE KI SABZI", price: 20 },
  { name: "KER SANGRI", price: 15 },
  { name: "PYAZ KACHORI", price: 15 },
];

export default function MumbaiModal({ onClose }) {
  // Lock background scroll
  useEffect(() => {
    document.body.style.overflow = "hidden";
    return () => {
      document.body.style.overflow = "";
    };
  }, []);

  return (
    <>
      {/* Overlay */}
      <div onClick={onClose} style={styles.overlay} />

      {/* Modal */}
      <div style={styles.modal}>
        {/* Close button */}
        <button onClick={onClose} style={styles.closeBtn}>
          ✕
        </button>

        {/* Background image */}
        <img src={mumbaiBg} alt="mumbai" style={styles.bgImage} />

        {/* Flower — top right */}
        <img src={flowerTopRight} alt="" style={styles.flowerTopRight} />

        {/* Flower — bottom left */}
        <img src={flowerBottomLeft} alt="" style={styles.flowerBottomLeft} />

        {/* City title with octagon border */}
        <div style={styles.titleRow}>
            <div style={styles.titleRow}>
  <div style={{ position: "absolute", zIndex: 3 }}><OctagonBorder /></div>
  <h1 style={styles.cityTitle}>mumbai</h1>
</div>

        </div>

        {/* Menu card */}
        <div style={styles.menuCard}>
          {MENU_ITEMS.map((item) => (
            <div key={item.name} style={styles.menuRow}>
              <span style={styles.menuName}>{item.name}</span>
              <span style={styles.menuSlash}>/</span>
              <span style={styles.menuPrice}>{item.price}</span>
            </div>
          ))}
        </div>
      </div>
    </>
  );
}

